190	TableAccessor TableQuery::Access(SyllableId syllable_id,
191	                                 double credibility,
192	                                 double quality_len) const {
193	  credibility += credibility_sum();
194	  quality_len += quality_len_sum();
195	  if (level_ == 0) {
196	    if (!lv1_index_ || syllable_id < 0 ||
197	        syllable_id >= static_cast<SyllableId>(lv1_index_->size))
198	      return TableAccessor();
199	    auto node = &lv1_index_->at[syllable_id];
200	    return TableAccessor(add_syllable(index_code_, syllable_id), &node->entries,
201	                         credibility, quality_len);
202	  } else if (level_ == 1 || level_ == 2) {
203	    auto index = (level_ == 1) ? lv2_index_ : lv3_index_;
204	    if (!index)
205	      return TableAccessor();
206	    auto node = find_node(index->begin(), index->end(), syllable_id);
207	    if (node == index->end())
208	      return TableAccessor();
209	    return TableAccessor(add_syllable(index_code_, syllable_id), &node->entries,
210	                         credibility, quality_len);
211	  } else if (level_ == 3) {
212	    if (!lv4_index_)
213	      return TableAccessor();
214	    return TableAccessor(index_code_, lv4_index_, credibility, quality_len);
215	  }
216	  return TableAccessor();
217	}
